            w.forEach((x) => { const n = x.b.checkOut ? dn(x.b.checkIn, x.b.checkOut) : 0; nights += n; revenue += total(x.b); byC[x.pk] = (byC[x.pk] || 0) + n; });
            return { nights, revenue, byC };
