            label: `${monthNm}: ${cur.nights} night${cur.nights === 1 ? '' : 's'} booked, ${trend}`,
            sub: `${gbp(cur.revenue)} in${top ? ' · ' + top : ''}${down ? ' · worth a nudge — maybe a last-minute offer' : ''}`,
