    try {
        renderDepositsDue();
    } catch (e) {}
    try {
        renderMoneyPanel();
    } catch (e) {}
    try {
        renderMoneyForecast();
    } catch (e) {}
    try {
        renderMoneyFeed();
    } catch (e) {}
    try {
        await loadExpenses();
    } catch (e) {}
    await renderAccounts();
