        kind: 'payment.request',
        to: booking.email,
        sendLabel: `Send ${kind === 'balance' ? 'balance' : 'deposit'} request`,
        fallbackConfirm: `Email ${booking.name || 'the guest'} a ${kind === 'balance' ? 'balance' : 'deposit'} payment request?`,
