// ---- Per-cottage review links for EXTERNAL (Airbnb/Vrbo) guests ----
// Each live, listed cottage gets a /review/<slug> page (review.php) the owner
// shares after a stay: the guest leaves a star review + their email/phone, which
// feeds the "book direct next year" follow-up. Rendered from the live list.
function renderReviewLinks() {
    const wrap = document.getElementById('review-links');
    if (!wrap) return;
    const origin = typeof SITE_ORIGIN === 'string' ? SITE_ORIGIN : location.origin;
    const keys = typeof liveCottageKeys === 'function' ? liveCottageKeys() : [];
    if (!keys.length) {
        wrap.innerHTML = '';
        return;
    }
    const rows = keys
        .map((k) => {
            const slug = (typeof COTTAGE_SLUGS === 'object' && COTTAGE_SLUGS[k]) || k;
            const name = (propertyMeta[k] || {}).name || k;
            const url = origin + '/review/' + slug;
            return `<div style="margin-bottom:14px;">
                        <div style="font-size:0.8rem;font-weight:600;color:var(--text-light);margin-bottom:5px;">${escapeHtml(name)}</div>
                        <div style="display:flex;gap:8px;align-items:center;">
                            <input class="input-glass" readonly id="revlink-${escapeHtml(k)}" data-act="selectSelf" value="${escapeHtml(url)}" title="${escapeHtml(name)} review link" aria-label="${escapeHtml(name)} review link" style="font-size:0.8rem;flex:1;min-width:0;">
                            <button class="btn-sm btn-edit" style="flex-shrink:0;" ${chbAttrs('copyReviewLink', k)}>Copy</button>
                        </div>
                    </div>`;
        })
        .join('');
    wrap.innerHTML = `<div style="border:1px solid var(--glass-border);border-radius:14px;padding:16px;margin:0 0 20px;background:var(--glass-bg);">
                <div style="font-size:0.75rem;text-transform:uppercase;letter-spacing:1px;color:var(--text-muted);margin-bottom:4px;">Review links to share with guests</div>
                <p style="font-size:0.8rem;color:var(--text-muted);margin:0 0 12px;line-height:1.5;">Send these to your Airbnb / Vrbo guests after they check out. They leave a review and their contact details — approved reviews appear on the site, and next year we'll invite them back to book direct.</p>
                ${rows}
            </div>`;
}
// Copy a cottage's review link (mirrors copyIcalExport).
async function copyReviewLink(key) {
    const el = document.getElementById('revlink-' + key);
    const url = el ? el.value : '';
    if (!url) return;
    let copied = false;
    try {
        await navigator.clipboard.writeText(url);
        copied = true;
    } catch (e) {
        /* clipboard blocked */
    }
    if (copied) toast('Review link copied — send it to your guest.');
    else {
        if (el) {
            el.focus();
            el.select();
        }
        await glassAlert('Copy this review link:\n\n' + url);
    }
}

// ---- External-guest reviews (direct_leads via the /review/<slug> links) ----
// Approve to publish on the site; privately rate the guest (hidden from them) to
// steer whether they get the book-direct follow-up next year.
const LEAD_SOURCE_LABEL = { airbnb: 'Airbnb', vrbo: 'Vrbo', bookingcom: 'Booking.com', direct: 'Direct' };
function leadStatusPill(s) {
    if (s === 'approved') return '<span style="color:var(--ok);font-weight:600;">Published</span>';
    if (s === 'declined') return '<span style="color:var(--text-muted);">Hidden</span>';
    return '<span style="color:var(--warn);font-weight:600;">Awaiting you</span>';
}
function leadCardHtml(l) {
    const stars = '★'.repeat(Math.max(1, Math.min(5, parseInt(l.stars) || 5)));
    const cott = (propertyMeta[l.prop_key] || {}).name || l.prop_key;
    const src = LEAD_SOURCE_LABEL[l.source] || 'Direct';
    const contact = [escapeHtml(l.email || ''), l.phone ? escapeHtml(l.phone) : ''].filter(Boolean).join(' · ');
    const ar = parseInt(l.admin_rating) || 0;
    const priv = [1, 2, 3, 4, 5]
        .map(
            (n) =>
                `<button type="button" data-n="${n}" ${chbAttrs('pickLeadStar', l.id, n)} aria-label="${n} star" style="font-size:19px;line-height:1;background:none;border:0;cursor:pointer;padding:1px;color:${ar >= n ? '#e0a12f' : '#dccfb9'};">★</button>`,
        )
        .join('');
    const actions =
        l.status === 'approved'
            ? `<button class="btn-sm btn-edit" ${chbAttrs('setLeadStatus', l.id, 'pending')}>Unpublish</button>`
            : `<button class="btn-sm btn-edit" ${chbAttrs('setLeadStatus', l.id, 'approved')}>Approve &amp; publish</button>` +
              (l.status === 'pending' ? `<button class="btn-sm btn-edit" ${chbAttrs('setLeadStatus', l.id, 'declined')}>Decline</button>` : '');
    const excluded = ar > 0 && ar < 3
        ? `<div style="font-size:0.72rem;color:var(--warn);margin-top:6px;">This guest won't be included in the book-direct follow-up.</div>`
        : '';
    return `<div style="border:1px solid var(--glass-border);border-radius:14px;padding:14px;margin-bottom:10px;background:var(--glass-bg);">
                <div style="display:flex;gap:10px;flex-wrap:wrap;align-items:center;font-size:0.82rem;">
                    <strong>${escapeHtml(l.name)}</strong>
                    <span style="color:var(--text-muted);">${escapeHtml(cott)}</span>
                    <span style="font-size:0.68rem;letter-spacing:.4px;text-transform:uppercase;color:var(--text-muted);border:1px solid var(--glass-border);border-radius:20px;padding:1px 8px;">${escapeHtml(src)}</span>
                    <span style="color:#d6a785;">${stars}</span>
                    <span style="margin-left:auto;">${leadStatusPill(l.status)}</span>
                </div>
                <div style="font-size:0.88rem;color:var(--text-muted);margin:8px 0;font-style:italic;">“${escapeHtml(l.review_text)}”</div>
                <div style="font-size:0.76rem;color:var(--text-muted);margin-bottom:10px;">${contact}</div>
                <div style="display:flex;gap:8px;flex-wrap:wrap;">${actions}
                    <button class="btn-sm btn-delete" ${chbAttrs('deleteLead', l.id)}>Delete</button>
                </div>
                <div style="margin-top:12px;border-top:1px dashed var(--glass-border);padding-top:12px;">
                    <div style="font-size:0.72rem;text-transform:uppercase;letter-spacing:.6px;color:var(--text-muted);margin-bottom:6px;">
                        <svg class="ic" viewBox="0 0 24 24" width="12" height="12" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true" style="vertical-align:-2px;"><rect x="3" y="11" width="18" height="11" rx="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/></svg>
                        Rate this guest — private, never shown to them</div>
                    <div class="lead-prate" data-id="${l.id}" data-val="${ar}" style="display:flex;gap:3px;margin-bottom:8px;">${priv}</div>
                    <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center;">
                        <input class="input-glass field-sm" id="lead-note-${l.id}" placeholder="Private note (optional)" value="${escapeHtml(l.admin_note || '')}" style="flex:1;min-width:160px;font-size:0.82rem;">
                        <button class="btn-sm btn-edit" ${chbAttrs('saveLeadRating', l.id)}>Save rating</button>
                    </div>
                    ${excluded}
                </div>
            </div>`;
}
function pickLeadStar(id, n) {
    const box = document.querySelector('.lead-prate[data-id="' + id + '"]');
    if (!box) return;
    box.dataset.val = n;
    box.querySelectorAll('button').forEach((b) => {
        b.style.color = parseInt(b.dataset.n) <= n ? '#e0a12f' : '#dccfb9';
    });
}
async function saveLeadRating(id) {
    const box = document.querySelector('.lead-prate[data-id="' + id + '"]');
    const noteEl = document.getElementById('lead-note-' + id);
    const val = box ? parseInt(box.dataset.val) || 0 : 0;
    try {
        await apiPost('leads.php', { action: 'rate_guest', id, admin_rating: val || null, admin_note: noteEl ? noteEl.value : '' });
        toast('Saved — only you can see this.');
        loadLeadModeration();
    } catch (e) {
        glassAlert("Couldn't save: " + e.message);
    }
}
async function setLeadStatus(id, status) {
    try {
        await apiPost('leads.php', { action: 'set_status', id, status });
        await loadLeadModeration();
        try {
            await loadPublicReviews();
            renderReviews();
        } catch (e2) {}
    } catch (e) {
        glassAlert("Couldn't update: " + e.message);
    }
}
async function deleteLead(id) {
    if (!(await glassConfirm('Delete this review permanently?'))) return;
    try {
        await apiPost('leads.php', { action: 'delete', id });
        await loadLeadModeration();
    } catch (e) {
        glassAlert("Couldn't delete: " + e.message);
    }
}
async function loadLeadModeration() {
    const wrap = document.getElementById('lead-moderation');
    if (!wrap) return;
    let rows = [];
    try {
        const r = await apiPost('leads.php', { action: 'list' });
        rows = r.leads || [];
    } catch (e) {
        wrap.innerHTML = ''; // table missing / not migrated — stay quiet
        return;
    }
    if (!rows.length) {
        wrap.innerHTML = '';
        return;
    }
    const pend = rows.filter((r) => r.status === 'pending').length;
    wrap.innerHTML =
        `<div style="display:flex;align-items:center;gap:8px;margin:4px 0 10px;">
            <h3 style="font-family:var(--font-serif);font-size:1.1rem;margin:0;">External guest reviews</h3>
            ${pend ? `<span style="font-size:0.72rem;font-weight:600;color:#fff;background:var(--warn);border-radius:20px;padding:2px 9px;">${pend} new</span>` : ''}
        </div>
        <p style="font-size:0.8rem;color:var(--text-muted);margin:0 0 12px;">Left via your review links. Approve to publish on the site; rate the guest privately to control who gets the book-direct follow-up.</p>` +
        rows.map(leadCardHtml).join('');
}

async function loadGuestReviewModeration() {
    initGoogleReviewUrl();
    renderReviewLinks();
    loadLeadModeration();
    // Set up the "import reviews from Airbnb & other sites" tools (always —
    // independent of whether there are on-site reviews to moderate).
    fillReviewImportControls();
    renderReviewsEditor();
    const wrap = document.getElementById('guest-review-moderation');
    if (!wrap) return;
    let rows = [];
    try {
        const r = await apiPost('reviews.php', { action: 'list_admin' });
        rows = r.reviews || [];
    } catch (e) {
        wrap.innerHTML = `<p style="font-size:0.85rem;color:var(--text-muted);">Couldn't load (run migration-guest-reviews.sql?): ${escapeHtml(e.message)}</p>`;
        return;
    }
    if (!rows.length) {
        wrap.innerHTML = emptyState({
            icon: '<path d="M12 3.5l2.6 5.27 5.82.85-4.21 4.1.99 5.78L12 17.77 6.8 19.5l.99-5.78-4.21-4.1 5.82-.85z"/>',
            title: 'No reviews yet',
            sub: 'Reviews you approve show on your website. Import your existing Airbnb reviews to get started.',
            actionLabel: 'Import reviews',
            onClick: 'data-act="bulkImportReviews"',
        });
        return;
    }

    const stars = (n) => '★'.repeat(Math.max(1, Math.min(5, parseInt(n) || 5)));
    const pending = rows.filter((r) => r.status === 'pending');

    // Pending reviews — shown in full, since these need your decision.
    const pendingHtml = pending.length
        ? pending
              .map(
                  (r) => `
                <div id="modrev-${r.id}" style="border:1px solid var(--glass-border);border-radius:14px;padding:14px;margin-bottom:10px;background:var(--glass-bg);">
                    <div style="display:flex;gap:10px;flex-wrap:wrap;align-items:center;font-size:0.82rem;">
                        <strong>${escapeHtml(r.name)}</strong>
                        <span style="color:var(--text-muted);">${escapeHtml((propertyMeta[r.prop_key] || {}).name || r.prop_key)}</span>
                        <span style="color:#d6a785;">${stars(r.stars)}</span>
                        <span style="color:var(--warn);">pending</span>
                    </div>
                    <div style="font-size:0.88rem;color:var(--text-muted);margin:8px 0;font-style:italic;">“${escapeHtml(r.review_text)}”</div>
                    <div style="display:flex;gap:8px;">
                        <button class="btn-sm btn-edit" ${chbAttrs('setReviewStatus', r.id, 'approved')}>Approve</button>
                        <button class="btn-sm btn-edit" ${chbAttrs('setReviewStatus', r.id, 'declined')}>Decline</button>
                        <button class="btn-sm btn-delete" ${chbAttrs('deleteGuestReview', r.id)}>Delete</button>
                    </div>
                </div>`,
              )
              .join('')
        : `<p style="font-size:0.85rem;color:var(--text-muted);"><svg class="ic" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="12" cy="12" r="9"/><path d="M8.5 12.5l2.5 2.5 4.5-5"/></svg> No reviews waiting — you're all caught up.</p>`;

    // Only reviews awaiting a decision are shown here. Approved reviews appear
    // on the public site; declined ones are simply hidden.
    wrap.innerHTML = pendingHtml;
}
async function setReviewStatus(id, status) {
    try {
        await apiPost('reviews.php', { action: 'set_status', id, status });
        await loadGuestReviewModeration();
        try {
            refreshModerationCounts();
        } catch (e2) {}
        await loadPublicReviews();
        renderReviews(); // refresh the public section
    } catch (e) {
        glassAlert("Couldn't update: " + e.message);
    }
}
async function deleteGuestReview(id) {
    if (!(await glassConfirm('Delete this guest review permanently?'))) return;
    try {
        await apiPost('reviews.php', { action: 'delete', id });
        await loadGuestReviewModeration();
        await loadPublicReviews();
        renderReviews();
    } catch (e) {
        glassAlert("Couldn't delete: " + e.message);
    }
}
function addReviewRow() {
    const wrap = document.getElementById('reviews-editor');
    if (wrap) wrap.insertAdjacentHTML('beforeend', reviewRowHtml(null));
}
// Populate the bulk-import dropdowns (cottages are dynamic, so build at open).
// Source defaults to Airbnb — the common case for a one-time import.
function fillReviewImportControls() {
    const propSel = document.getElementById('bulk-rev-prop');
    if (propSel)
        propSel.innerHTML =
            '<option value="">(no cottage)</option>' +
            Object.keys(propertyMeta)
                .map((k) => `<option value="${k}">${escapeHtml(propertyMeta[k].name)}</option>`)
                .join('');
    const srcSel = document.getElementById('bulk-rev-source');
    if (srcSel)
        srcSel.innerHTML = ['Airbnb', 'Vrbo', 'Booking.com', 'Google', 'Email', 'Guestbook', '']
            .map(
                (s) =>
                    `<option value="${s}" ${s === 'Airbnb' ? 'selected' : ''}>${s || '(no source)'}</option>`,
            )
            .join('');
    const starSel = document.getElementById('bulk-rev-stars');
    if (starSel)
        starSel.innerHTML = [5, 4, 3]
            .map((n) => `<option value="${n}">${'★'.repeat(n)}</option>`)
            .join('');
}
// One-time bulk import: parse pasted reviews (one per blank-line-separated block)
// into editable rows in #reviews-editor. Forgiving by design — the owner reviews
// every row before saving, so we favour "add something sensible" over strictness.
//   • A line that's only ★ chars or "5 stars" / "5/5" sets that review's rating.
//   • A standalone date / "2 weeks ago" / "Reviewed…" line is dropped.
//   • First remaining line → name, the rest → the review text.
//   • A single-line block becomes the review text with a blank name to fill in.
function bulkImportReviews() {
    const ta = document.getElementById('bulk-rev-text');
    const raw = ((ta && ta.value) || '').trim();
    if (!raw) {
        glassAlert('Paste your reviews into the box first.');
        return;
    }
    const prop = (document.getElementById('bulk-rev-prop') || {}).value || '';
    const source = (document.getElementById('bulk-rev-source') || {}).value || '';
    const defStars = parseInt((document.getElementById('bulk-rev-stars') || {}).value) || 5;
    const wrap = document.getElementById('reviews-editor');
    if (!wrap) return;

    const isStarLine = (l) =>
        /^[★☆\s]*★[★☆\s]*$/.test(l) || /^\s*[1-5]\s*(?:\/\s*5|stars?|★)/i.test(l);
    const starsFrom = (l) => {
        const c = (l.match(/★/g) || []).length;
        if (c) return c;
        const m = l.match(/[1-5]/);
        return m ? parseInt(m[0]) : defStars;
    };
    // A month only counts as a DATE when paired with a number (year or day) — so
    // real names like "Mark", "May", "April", "June" or "Janet" are NOT dropped.
    const MONTH =
        '(?:jan(?:uary)?|feb(?:ruary)?|mar(?:ch)?|apr(?:il)?|may|jun(?:e)?|jul(?:y)?|aug(?:ust)?|sep(?:t(?:ember)?)?|oct(?:ober)?|nov(?:ember)?|dec(?:ember)?)';
    const monthYear = new RegExp('^\\s*' + MONTH + '\\.?\\s+\\d{4}\\s*$', 'i'); // "October 2024"
    const dayMonth = new RegExp(
        '^\\s*\\d{1,2}(?:st|nd|rd|th)?\\s+' + MONTH + '(?:\\.?\\s+\\d{4})?\\s*$',
        'i',
    ); // "12 May", "2 March 2024"
    const isMetaLine = (l) =>
        monthYear.test(l) ||
        dayMonth.test(l) ||
        /^\s*\d{1,2}[\/.\-]\d{1,2}[\/.\-]\d{2,4}\s*$/.test(l) || // 12/05/2024
        /\b(?:days?|weeks?|months?|years?)\s+ago\b/i.test(l) || // "2 weeks ago"
        /^\s*(?:reviewed|stayed|response from)\b/i.test(l); // dashboard chrome

    const blocks = raw
        .split(/\n\s*\n+/)
        .map((b) => b.trim())
        .filter(Boolean);
    let added = 0;
    for (const block of blocks) {
        let lines = block
            .split('\n')
            .map((l) => l.trim())
            .filter(Boolean);
        let stars = defStars;
        const si = lines.findIndex(isStarLine);
        if (si !== -1) {
            stars = starsFrom(lines[si]);
            lines.splice(si, 1);
        }
        stars = Math.max(3, Math.min(5, stars)); // the row editor only offers 3–5
        lines = lines.filter((l) => !isMetaLine(l));
        if (!lines.length) continue;
        let name = '',
            text = '';
        if (lines.length === 1) {
            text = lines[0];
        } else {
            name = lines[0].replace(/[\s:\-–—]+$/, '').slice(0, 80);
            text = lines.slice(1).join(' ');
        }
        text = text.trim();
        if (!text) continue;
        wrap.insertAdjacentHTML('beforeend', reviewRowHtml({ name, stars, text, prop, source }));
        added++;
    }
    if (!added) {
        glassAlert(
            "Couldn't find any reviews to add — check the format: the guest's name on the first line, their review underneath, and a blank line between each one.",
        );
        return;
    }
    ta.value = '';
    toast(
        added +
            ' review' +
            (added === 1 ? '' : 's') +
            ' added below — check them over, then “Save imported reviews”.',
    );
    wrap.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
}
async function saveReviews() {
    const wrap = document.getElementById('reviews-editor');
    if (!wrap) return;
    const reviews = [];
    for (const row of wrap.querySelectorAll('.review-row')) {
        const get = (f) => {
            const el = row.querySelector(`[data-rf="${f}"]`);
            return el ? el.value : '';
        };
        const text = get('text').trim();
        if (!text) continue; // empty review — skip
        reviews.push({
            name: get('name').trim(),
            stars: parseInt(get('stars')) || 5,
            text,
            prop: get('prop'),
            source: get('source'),
        });
    }
    try {
        await saveContent('reviews', reviews);
        siteContent.reviews = reviews;
        renderReviews();
        toast('Reviews saved.');
    } catch (e) {
        glassAlert("Couldn't save reviews: " + e.message);
    }
}

// ---- Seasonal rates editor (Settings) ----
// ---- Season grid: every cottage's seasonal pricing on one screen ----
// Rows are date bands (label + start + end) shared across the grid;
// columns are the live cottages. A blank cell means that cottage simply
// has no seasonal rate for that band (its base rate applies).
function seasonGridBands() {
    const bands = new Map();
    liveCottageKeys().forEach((k) =>
        (propertySeasons[k] || []).forEach((s) => {
            const key = `${s.start_date}|${s.end_date}|${s.label || ''}`;
            if (!bands.has(key))
                bands.set(key, {
                    label: s.label || '',
                    start: s.start_date,
                    end: s.end_date,
                    rates: {},
                });
            bands.get(key).rates[k] = parseFloat(s.couple_rate);
        }),
    );
    return [...bands.values()].sort((a, b) => (a.start || '').localeCompare(b.start || ''));
}
function seasonGridRowHtml(b) {
    const keys = liveCottageKeys();
    return `
                <tr class="sg-band">
                    <td data-label="Season"><input type="text" class="input-glass field-sm" value="${escapeHtml(b.label)}" data-sg="label" placeholder="e.g. Summer"></td>
                    <td data-label="From"><input type="date" class="input-glass field-sm" value="${b.start || ''}" data-sg="start"></td>
                    <td data-label="Until"><input type="date" class="input-glass field-sm" value="${b.end || ''}" data-sg="end"></td>
                    ${keys.map((k) => `<td data-label="${escapeHtml(propertyMeta[k].short || propertyMeta[k].name || k)}"><input type="number" class="input-glass field-sm sg-rate" min="0" step="1" placeholder="—" value="${b.rates[k] || ''}" data-sg-prop="${k}" title="${escapeHtml(propertyMeta[k].name)} £/night (couple)"></td>`).join('')}
                    <td class="sg-del"><button class="btn-sm btn-delete" data-act="closestRemove" data-sel="tr" title="Remove this season everywhere"><svg class="ic" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M6 6l12 12M18 6L6 18"/></svg></button></td>
                </tr>`;
}
function renderSeasonGrid() {
    const wrap = document.getElementById('season-grid-wrap');
    if (!wrap) return;
    const keys = liveCottageKeys();
    const bands = seasonGridBands();
    wrap.innerHTML = `
                <div style="overflow-x:auto;">
                <table class="sg-table">
                    <thead><tr>
                        <th style="min-width:120px;">Season</th><th>From</th><th>Until</th>
                        ${keys.map((k) => `<th style="min-width:86px;"><span class="prop-tag tag-${k}">${propertyMeta[k].short}</span></th>`).join('')}
                        <th></th>
                    </tr></thead>
                    <tbody id="season-grid-body">${
                        bands.length
                            ? bands.map(seasonGridRowHtml).join('')
                            : seasonGridRowHtml({ label: '', start: '', end: '', rates: {} })
                    }</tbody>
                </table>
                </div>
                <div style="display:flex;gap:10px;flex-wrap:wrap;margin-top:14px;">
                    <button class="btn-sm btn-edit" data-act="addSeasonGridRow">+ Add a season</button>
                    <button class="btn-glass" style="width:auto;padding:11px 24px;" data-act="saveSeasonGrid">Save all cottages</button>
                    <span id="season-grid-msg" style="font-size:0.82rem;align-self:center;"></span>
                </div>
                <p style="font-size:0.78rem;color:var(--text-muted);margin:12px 0 0;max-width:640px;">Each cell is that cottage's nightly couple rate for the season. Leave a cell blank and the cottage keeps its normal base rate for those dates. Deleting a row removes the season from every cottage when you save.</p>`;
}
function addSeasonGridRow() {
    const body = document.getElementById('season-grid-body');
    if (body)
        body.insertAdjacentHTML(
            'beforeend',
            seasonGridRowHtml({ label: '', start: '', end: '', rates: {} }),
        );
}
async function saveSeasonGrid() {
    const body = document.getElementById('season-grid-body');
    if (!body) return;
    const keys = liveCottageKeys();
    const perProp = {};
    keys.forEach((k) => (perProp[k] = []));
    for (const tr of body.querySelectorAll('tr')) {
        const get = (sel) => {
            const el = tr.querySelector(sel);
            return el ? el.value.trim() : '';
        };
        const label = get('[data-sg="label"]'),
            start = get('[data-sg="start"]'),
            end = get('[data-sg="end"]');
        const rates = keys.map((k) => {
            const el = tr.querySelector(`[data-sg-prop="${k}"]`);
            return { k, rate: el ? parseFloat(el.value) || 0 : 0 };
        });
        if (!start && !end && !label && rates.every((r) => !r.rate)) continue; // fully empty row
        if (!start || !end) {
            glassAlert(`"${label || 'A season'}" needs both a start and an end date.`);
            return;
        }
        if (end < start) {
            glassAlert(`"${label || 'A season'}" ends before it starts — check the dates.`);
            return;
        }
        rates.forEach(({ k, rate }) => {
            if (rate > 0) perProp[k].push({ label, start, end, rate });
        });
    }
    const msg = document.getElementById('season-grid-msg');
    try {
        for (const k of keys) {
            await apiPost('rates.php', {
                action: 'seasons_save',
                prop_key: k,
                seasons: perProp[k],
            });
            propertySeasons[k] = perProp[k].map((s) => ({
                label: s.label,
                start_date: s.start,
                end_date: s.end,
                couple_rate: s.rate,
            }));
        }
        renderCardPrices();
        updatePropPriceHeading();
        if (msg) {
            msg.textContent = 'Saved for all cottages ✓';
            msg.style.color = 'var(--ok-text)';
            setTimeout(() => {
                msg.textContent = '';
            }, 4000);
        }
        toast('Seasonal rates saved for all cottages.');
    } catch (e) {
        glassAlert("Couldn't save: " + e.message);
    }
}
// ---- Dashboard: warn the owner if the daily automation has stopped ----
// Reads cron-status.php (stamped by cron.php on every real run). Only the
// banner appears, and only when things are genuinely quiet, so a healthy
// site shows nothing.
async function checkCronHealth() {
    const el = document.getElementById('cron-alert');
    const pill = document.getElementById('cron-pill');
    if (!el) return;
    let d;
    try {
        // loadData's admin-bootstrap round-trip stashes the cron status (it runs
        // just before this on the dashboard), so no extra request is needed;
        // fetch directly only when it's absent.
        d = window.__cronStatusPre || (await apiGet('cron-status.php'));
    } catch (e) {
        el.style.display = 'none';
        if (pill) pill.style.display = 'none';
        return;
    }
    // Exception-only pill: healthy automation stays hidden (a green "all fine"
    // badge is just noise); it appears amber only when the daily job has gone
    // quiet. A hard failure still raises the loud banner below.
    if (pill && d) {
        if (d.stale) {
            const ago = !d.everRan
                ? 'never run'
                : d.ageHours >= 48
                  ? Math.round(d.ageHours / 24) + ' days ago'
                  : d.ageHours >= 1.5
                    ? Math.round(d.ageHours) + ' h ago'
                    : 'just now';
            pill.className = 'cron-pill warn';
            pill.innerHTML = `<span class="cron-pill-dot"></span>Automation quiet · ${ago}`;
            pill.style.display = '';
        } else {
            pill.style.display = 'none';
        }
    }
    __nyCronQuiet = !!(d && d.stale);
    try {
        renderNeedsYou();
    } catch (e) {}
    if (!d || !d.stale) {
        el.style.display = 'none';
        return;
    }
    const detail = d.everRan
        ? `last ran ${d.ageHours >= 48 ? Math.round(d.ageHours / 24) + ' days' : Math.round(d.ageHours) + ' hours'} ago`
        : 'it has never run';
    el.innerHTML = `
                <svg class="ic" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 9v4M12 17h.01M10.3 3.9 1.8 18a2 2 0 0 0 1.7 3h17a2 2 0 0 0 1.7-3L13.7 3.9a2 2 0 0 0-3.4 0z"/></svg>
                <div>
                    <strong>Your daily automation looks stopped</strong> — ${detail}. While it's off, pre-arrival emails, balance reminders, guest re-invites and weekly backups won't send.
                    <div style="margin-top:6px;font-size:0.85rem;">Check the scheduled task at your host still points at <code>cron.php</code>, then open <a data-act="navDiagnostics" style="cursor:pointer;text-decoration:underline;">Status</a>.</div>
                </div>`;
    el.style.display = '';
}
// ---- Dashboard: one-glance systems-health pill ----
// Rolls up the full Status page (diagnostics.php: DB, mail, Square, cron,
// backup, migrations, error rate …) into a single dashboard signal so trouble
// surfaces without visiting System check. Green = all clear; amber = something
// needs a look; red = a hard failure. Tap opens the full Status page. Cached
// for the session so the (heavier) diagnostics scan runs at most once per visit.
async function checkSystemHealth() {
    const pill = document.getElementById('health-pill');
    if (!pill) return;
    let d;
    try {
        const cached = sessionStorage.getItem('chb-health');
        d = cached ? JSON.parse(cached) : null;
    } catch (e) {}
    if (!d) {
        try {
            const r = await apiGet('diagnostics.php');
            d = r && r.summary ? r.summary : null;
            if (d) {
                try {
                    sessionStorage.setItem('chb-health', JSON.stringify(d));
                } catch (e) {}
            }
        } catch (e) {
            pill.style.display = 'none';
            return;
        }
    }
    if (!d) {
        pill.style.display = 'none';
        return;
    }
    const fail = d.fail || 0;
    const warn = d.warn || 0;
    if (fail > 0) {
        pill.className = 'cron-pill danger';
        pill.innerHTML = `<span class="cron-pill-dot"></span>${fail} system issue${fail === 1 ? '' : 's'} — tap to check`;
    } else if (warn > 0) {
        pill.className = 'cron-pill warn';
        pill.innerHTML = `<span class="cron-pill-dot"></span>${warn} thing${warn === 1 ? '' : 's'} need${warn === 1 ? 's' : ''} a look`;
    } else {
        // No failures and no actionable warnings (optional/off features don't
        // count) → the calm green "all clear" state.
        pill.className = 'cron-pill ok';
        pill.innerHTML = `<span class="cron-pill-dot"></span>All systems operational`;
    }
    pill.style.display = '';
}
// ---- Dashboard: recent-activity feed ----
function timeAgoLabel(at) {
    try {
        const d = new Date(String(at).replace(' ', 'T'));
        const mins = Math.max(0, Math.round((Date.now() - d.getTime()) / 60000));
        if (mins < 60) return mins <= 1 ? 'just now' : `${mins} min ago`;
        const hrs = Math.round(mins / 60);
        if (hrs < 24) return `${hrs} h ago`;
        const days = Math.round(hrs / 24);
        if (days < 8) return days === 1 ? 'yesterday' : `${days} days ago`;
        return d.toLocaleDateString('en-GB', { day: 'numeric', month: 'short' });
    } catch (e) {
        return '';
    }
}
