            const p =
                b.agreedPrice ||
                priceBreakdown(loc.propKey, b.adults, b.children, b.checkIn, b.checkOut);
            const ps = paymentSummary(loc.propKey, b);
            const gt = displayGrand(p, ps, b.holdStatus);
            const status = gt.fullyPaid
                ? 'Paid in full'
                : gt.paid > 0
